INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Techniques de vente & négociation commerciale', 'Formation sur l’intégration de l’IA dans le management commercial pour optimiser la performance et la prise de décision.', 3, 200000.00, 'entreprise', '2026-11-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre l’impact de l’IA sur le management\n• Utiliser des outils IA pour suivre et améliorer la performance des équipes\n• Automatiser les tâches de gestion et reporting\n• Prendre des décisions basées sur les données et recommandations IA\n• Développer une culture d’équipe orientée innovation et résultats\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre le rôle de l’IA dans le management commercial, utiliser des outils IA pour optimiser la performance, automatiser les tâches de gestion, prendre des décisions basées sur les données et développer une culture d’équipe innovante.\n\n--- PRÉREQUIS ---\nExpérience préalable en management ou gestion d’équipe souhaitée. Familiarité avec les outils numériques recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA appliquée au management\nModule 2 : Pilotage et suivi des équipes avec l’IA\nModule 3 : Prise de décision managériale basée sur l’IA\nModule 4 : Optimisation des pratiques managériales\nModule 5 : Développement d’une culture managériale orientée IA\nModule 6 : Plan d’action individuel\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nManagers commerciaux, responsables d’équipes, chefs de ventes, directeurs de secteur, responsables CRM et performance commerciale.\n\n--- MÉTHODES ---\nExposés interactifs, démonstrations, études de cas, ateliers pratiques, simulations de décisions assistées par IA et discussions collectives.\n\n--- SUPPORTS ---\nSlides interactives, outils IA, guides pratiques, modèles de tableaux de bord, études de cas et vidéos pédagogiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
